286	  /** POST /tests/generate (auth) */
287	  async generateTest(req: Request, res: Response): Promise<void> {
288	    const dto: IGenerateTestDTO = req.body;
289	    const userId = (req as any).user?.userId;
290	    await assertLearnerSubjectAccess(userId, dto.subjectId);
291	    await roadmapService.assertKnowledgeMapTestAllowed(userId, dto.subjectId, dto.roadmapNodeId);
292	    const profile = this.normalizeTestProfile(dto);
293	    const { contentForAI, book } = await resolveBookContentForAI(dto);
294	
295	    // Точный кэш по контенту: тот же материал → тот же тест (без лишнего LLM-вызова).
296	    if (!dto.forTrial) {
297	      const hash = aiService.computeTestContentHash(contentForAI.text, profile, dto.questionCount);
298	      const cached = await this.findCachedTest(dto, profile, hash);
299	      if (cached) {
300	        success(res, this.sanitize(cached), 'Test loaded from cache (same content)', 201);
301	        return;
302	      }
303	    }
304	
305	    const user = await User.findById(userId);
306	    const previousQuestions = user?.getAllQuestionHashes(dto.subjectId, dto.bookId) || [];
307	
308	    const genOpts =
309	      typeof dto.questionCount === 'number' && dto.questionCount > 0
310	        ? { questionCount: dto.questionCount }
311	        : undefined;
312	    const generated = await aiService.generateTest(contentForAI, previousQuestions, profile, genOpts);
313	    this.resolveTopicTitleToId(generated, book);
314	    const test = await this.findOrCreateTest(dto, generated, !dto.forTrial);
315	    success(res, this.sanitize(test), 'Test generated successfully', 201);
316	  }
