318	  /**
319	   * POST /tests/submit (auth) — ЛЁГКИЙ submit.
320	   * Считает только результат и сохраняет историю (без AI). Разбор, темы для повторения и
321	   * AI-объяснение клиент тянет лениво по testHistoryId:
322	   *   GET /users/me/tests/:id/breakdown        — по-вопросный разбор + темы для повторения
323	   *   GET /users/me/tests/:id/ai-explanation   — AI-feedback (считается и кэшируется при первом запросе)
324	   */
325	  async submitTest(req: Request, res: Response): Promise<void> {
326	    const { testId, answers, roadmapNodeId, roadmapSessionId, forTrial }: ISubmitTestDTO = req.body;
327	    const userId = (req as any).user?.userId;
328	
329	    const test = await Test.findById(testId);
330	    if (!test) throw AppError.notFound('Test not found');
331	    await assertLearnerSubjectAccess(userId, test.subjectId.toString());
332	
333	    const { userAnswers, result: resultSummary } = this.checkAnswers(test, answers);
334	    const trialExtra = await this.trialTopicMasteryPayload(Boolean(forTrial), test, userAnswers);
335	
336	    // Пер-KC mastery + статистика банка (только для тестов с KC-тегами; иначе no-op).
337	    try {
338	      await userKcMasteryService.recordFromSubmission(
339	        userId,
340	        test.subjectId.toString(),
341	        test.questions as IQuestion[],
342	        userAnswers
343	      );
344	    } catch (err) {
345	      console.error('[submitTest] KC mastery update failed:', err);
346	    }
347	
348	    const questionHashes = test.questions.map((q) => Buffer.from(q.questionText).toString('base64'));
349	    const testHistory: ITestHistory = {
350	      testId: test._id,
351	      subjectId: test.subjectId,
352	      bookId: test.bookId,
353	      chapterId: test.chapterId,
354	      generatedQuestionsHash: questionHashes,
355	      answers: userAnswers,
356	      result: resultSummary
357	      // aiFeedback не считаем на submit — ленивая генерация в /ai-explanation
358	    };
359	
360	    const updated = await User.findByIdAndUpdate(
361	      userId,
362	      { $push: { testHistory } },
363	      { new: true, select: 'testHistory' }
364	    );
365	    const savedEntry = updated?.testHistory?.[updated.testHistory.length - 1];
366	    const testHistoryId = savedEntry?._id ? String(savedEntry._id) : undefined;
367	
368	    let roadmap: Awaited<ReturnType<typeof roadmapService.recordTestSubmitted>> | undefined;
369	    if (roadmapNodeId?.trim() && roadmapSessionId?.trim()) {
370	      try {
371	        roadmap = await roadmapService.recordTestSubmitted({
372	          userId,
373	          subjectId: test.subjectId.toString(),
374	          nodeId: roadmapNodeId.trim(),
375	          scorePercent: resultSummary.scorePercent,
376	          sessionId: roadmapSessionId.trim(),
377	          submittedAt: new Date()
378	        });
379	      } catch (err) {
380	        console.error('[submitTest] roadmap update failed:', err);
381	      }
382	    }
383	
384	    success(
385	      res,
386	      {
387	        testHistoryId,
388	        testId: test._id,
389	        result: resultSummary,
390	        ...trialExtra,
391	        ...(roadmap ? { roadmap } : {})
392	      },
393	      'Test submitted successfully'
394	    );
395	  }
