414	  /** POST /tests/solo/start (auth) */
415	  async startSoloTest(req: Request, res: Response): Promise<void> {
416	    const dto: IGenerateTestDTO & { mode: 'daily_pack' | 'practice' } = req.body;
417	    const userId = (req as any).user?.userId;
418	    await assertLearnerSubjectAccess(userId, dto.subjectId);
419	    await roadmapService.assertKnowledgeMapTestAllowed(userId, dto.subjectId, dto.roadmapNodeId);
420	    const mode = dto.mode === 'practice' ? 'practice' : 'daily_pack';
421	    const dateKey = this.getDateKey();
422	    const dailyPackId = this.buildDailyPackId({
423	      subjectId: dto.subjectId,
424	      bookId: dto.bookId,
425	      chapterId: dto.chapterId,
426	      fullBook: dto.fullBook,
427	      testProfile: this.normalizeTestProfile(dto),
428	      dateKey
429	    });
430	
431	    let test = await Test.findOne({
432	      subjectId: dto.subjectId,
433	      bookId: dto.bookId,
434	      chapterId: dto.chapterId || { $exists: false },
435	      testProfile: this.normalizeTestProfile(dto),
436	      sourceContentHash: dailyPackId
437	    }).sort({ createdAt: -1 });
438	
439	    if (!test) {
440	      const { contentForAI, book } = await resolveBookContentForAI(dto);
441	      const generated = await aiService.generateTest(contentForAI, [], this.normalizeTestProfile(dto));
442	      this.resolveTopicTitleToId(generated, book);
443	      test = await Test.create({
444	        subjectId: dto.subjectId,
445	        bookId: dto.bookId,
446	        chapterId: dto.chapterId || undefined,
447	        questions: generated.questions,
448	        sourceContentHash: dailyPackId,
449	        testProfile: this.normalizeTestProfile(dto)
450	      });
451	    }
452	
453	    /** Один ranked daily pack в календарный день на пользователя, независимо от предмета/книги */
454	    const rankedDailyUsedToday = await SoloAttempt.exists({
455	      userId,
456	      attemptType: 'ranked',
457	      createdAt: { $gte: this.startOfToday() }
458	    });
459	
460	    if (mode === 'daily_pack' && rankedDailyUsedToday) {
461	      throw AppError.badRequest(
462	        'Сегодня вы уже прошли daily pack (доступна одна попытка в день). Выберите Practice или вернитесь завтра.'
463	      );
464	    }
465	
466	    const attemptType = mode === 'daily_pack' ? 'ranked' : 'practice';
467	    const session = await SoloSession.create({
468	      userId,
469	      testId: test._id,
470	      dailyPackId,
471	      mode,
472	      attemptType,
473	      questionTimeLimitSec: TestController.SOLO_QUESTION_TIME_LIMIT_SEC,
474	      currentQuestionIndex: 0,
475	      questionStartedAt: new Date(),
476	      answers: [],
477	      isFinished: false
478	    });
479	
480	    success(
481	      res,
482	      {
483	        ...this.sanitize(test),
484	        mode,
485	        dailyPackId,
486	        attemptType,
487	        soloSessionId: session._id,
488	        soloCurrentQuestionIndex: 0,
489	        soloQuestionStartedAt: session.questionStartedAt,
490	        rankedUsedToday: Boolean(rankedDailyUsedToday),
491	        questionTimeLimitSec: TestController.SOLO_QUESTION_TIME_LIMIT_SEC
492	      },
493	      'Solo test started',
494	      201
495	    );
496	  }
