498	  /** POST /tests/solo/answer (auth) */
499	  async submitSoloAnswer(req: Request, res: Response): Promise<void> {
500	    const userId = (req as any).user?.userId;
501	    const { soloSessionId, questionIndex, selectedOption }: {
502	      soloSessionId: string;
503	      questionIndex: number;
504	      selectedOption: string;
505	    } = req.body;
506	
507	    const session = await SoloSession.findById(soloSessionId);
508	    if (!session) throw AppError.notFound('Solo session not found');
509	    if (session.userId.toString() !== userId) throw AppError.forbidden('Access denied');
510	    if (session.isFinished) throw AppError.badRequest('Solo session already finished');
511	    if (session.currentQuestionIndex !== questionIndex) {
512	      throw AppError.badRequest('Question index mismatch');
513	    }
514	
515	    const test = await Test.findById(session.testId);
516	    if (!test) throw AppError.notFound('Test not found');
517	
518	    const question = test.questions[questionIndex];
519	    if (!question) throw AppError.badRequest('Invalid question index');
520	
521	    const elapsedMs = Math.max(0, Date.now() - session.questionStartedAt.getTime());
522	    const cappedMs = Math.min(elapsedMs, session.questionTimeLimitSec * 1000);
523	    const isCorrect = gradeAnswer(question as IQuestion, selectedOption || '');
524	    const questionScore = this.calculateSoloQuestionScore(isCorrect, cappedMs);
525	
526	    const nextIndex = questionIndex + 1;
527	    const isLastQuestion = nextIndex >= test.questions.length;
528	
529	    session.answers.push({
530	      questionIndex,
531	      selectedOption: selectedOption || '',
532	      isCorrect,
533	      responseTimeMs: cappedMs,
534	      questionScore
535	    });
536	    session.currentQuestionIndex = nextIndex;
537	    session.questionStartedAt = new Date();
538	    if (isLastQuestion) session.isFinished = true;
539	    await session.save();
540	
541	    success(res, {
542	      accepted: true,
543	      questionIndex,
544	      isCorrect,
545	      questionScore,
546	      responseTimeMs: cappedMs,
547	      finished: isLastQuestion,
548	      nextQuestionIndex: isLastQuestion ? null : nextIndex,
549	      questionStartedAt: isLastQuestion ? null : session.questionStartedAt
550	    }, 'Solo answer accepted');
551	  }
