29	/**
30	 * Ключ дедупа item'а: текст + (отсортированные) варианты + правильный ответ.
31	 * Включение вариантов ловит перефразировки-с-теми-же-опциями, которые text-only хэш пропускал.
32	 */
33	function contentHashOf(q: IQuestion): string {
34	  const norm = (s: string): string => s.trim().toLowerCase().replace(/\s+/g, ' ');
35	  const parts = [
36	    norm(q.questionText),
37	    ...(q.options ?? []).map(norm).sort(),
38	    `=${norm(q.correctOption ?? '')}`
39	  ];
40	  return createHash('sha256').update(parts.join('|')).digest('hex');
41	}
