43	/** Старый (v1) ключ дедупа — только по тексту. Для переходной дедупликации против pre-v2 item'ов. */
44	function legacyContentHashOf(questionText: string): string {
45	  const norm = questionText.trim().toLowerCase().replace(/\s+/g, ' ');
46	  return createHash('sha256').update(norm).digest('hex');
47	}
