49	/**
50	 * Разложить дефицит на уровни сложности вокруг центра (для разброса в банке —
51	 * иначе адаптивному отбору нечем варьировать сложность). Малый дефицит не размазываем.
52	 */
53	function buildDifficultyPlan(count: number, center: number): Array<{ difficulty: number; count: number }> {
54	  if (count <= 0) return [];
55	  if (count <= 2) return [{ difficulty: center, count }];
56	  const levels = [...new Set([Math.max(1, center - 1), center, Math.min(5, center + 1)])];
57	  const plan = levels.map((difficulty) => ({ difficulty, count: 0 }));
58	  for (let i = 0; i < count; i++) plan[i % plan.length].count++;
59	  return plan.filter((p) => p.count > 0);
60	}
