259	              producedThisRound++;
260	            } catch (e: unknown) {
261	              // Дубликат (уникальный индекс по contentHash в узле) — молча пропускаем.
262	              if ((e as { code?: number }).code === 11000) continue;
263	              console.warn('[questionBank] insert failed', e);
264	            }
265	          }
266	        }
267	      }
268	      if (producedThisRound === 0) break; // прогресса нет — не крутим вхолостую
269	    }
270	
271	    if (rejectReasons.length) {
272	      console.warn(`[questionBank] отклонено верификатором: ${rejected}. Примеры причин:`);
273	      for (const r of rejectReasons.slice(0, 8)) console.warn('   •', r);
274	    }
275	
276	    const coverageAfter = await this.coverage(subjectId, ktpTopicId);
277	    return { created, rejected, coverage: coverageAfter };
278	  }
279	
280	  /**
281	   * Собрать тест из банка по покрытию KC (round-robin), при нехватке — дозаполнить и пересобрать.
282	   * Возвращает обычный Test-документ (переиспользует существующий submit/grade пайплайн).
283	   */
284	  async assembleNodeTest(
285	    subjectId: string,
286	    ktpTopicId: string,
287	    opts?: { userId?: string; size?: number }
288	  ): Promise<InstanceType<typeof Test>> {
289	    await this.assertSubject(subjectId);
290	    const size = normalizeTestSize(opts?.size);
291	
292	    // Адаптивный контекст: пер-KC mastery (слабые темы вперёд) + недавние item'ы (SR).
293	    const ctx = opts?.userId
294	      ? {
295	          componentMap: await userKcMasteryService.getComponentMap(opts.userId, subjectId),
296	          recentItems: await userKcMasteryService.getRecentItemIds(opts.userId, subjectId)
297	        }
298	      : undefined;
299	
300	    let items = await this.selectCovering(subjectId, ktpTopicId, size, ctx);
301	    if (items.length < size) {
302	      // дозаполняем банк под нужный размер (минимум на KC масштабируем от size) и пробуем ещё раз
303	      const cov = await this.coverage(subjectId, ktpTopicId);
304	      const kcCount = Math.max(1, cov.perKc.length);
305	      const minPerKc = Math.max(DEFAULT_MIN_ITEMS_PER_KC, Math.ceil(size / kcCount));
306	      await this.generateForCoverage(subjectId, ktpTopicId, { minPerKc });
307	      items = await this.selectCovering(subjectId, ktpTopicId, size, ctx);
308	    }
309	    if (items.length < size) {
310	      throw AppError.badRequest(
311	        `Недостаточно вопросов в банке для сборки теста (есть ${items.length} из ${size}). Сгенерируйте больше.`
312	      );
313	    }
314	
315	    const resolved = await this.resolveNode(subjectId, ktpTopicId);
316	    if (!resolved.primary.bookId) throw AppError.badRequest('Node has no primary book to attach test');
317	
318	    const selected = items.slice(0, size);
319	    const sourceContentHash =
320	      `bank:${size}:` +
321	      createHash('sha256')
322	        .update(`${size}|` + selected.map((i) => String(i._id)).sort().join(','))
323	        .digest('hex');
324	
325	    // Реюз: та же выборка → тот же тест.
326	    const existing = await Test.findOne({ subjectId, sourceContentHash }).sort({ createdAt: -1 });
327	    if (existing) return existing;
328	
329	    const questions: IQuestion[] = selected.map((it) => {
330	      const q = it.question as IQuestion;
331	      return {
332	        ...q,
333	        relatedContent: {
334	          ...q.relatedContent,
335	          ...(resolved.primary.chapterId
336	            ? { chapterId: new mongoose.Types.ObjectId(resolved.primary.chapterId) }
337	            : {})
338	        },
339	        questionItemId: it._id as mongoose.Types.ObjectId,
340	        ...(it.knowledgeComponentIds?.length ? { knowledgeComponentIds: it.knowledgeComponentIds } : {})
341	      };
342	    });
343	
344	    await QuestionItem.updateMany(
345	      { _id: { $in: selected.map((i) => i._id) } },
346	      { $inc: { 'qualityStats.timesUsed': 1 } }
347	    );
348	
349	    return Test.create({
350	      subjectId,
351	      bookId: resolved.primary.bookId,
352	      ...(resolved.primary.chapterId ? { chapterId: resolved.primary.chapterId } : {}),
353	      questions,
354	      sourceContentHash,
355	      testProfile: 'ent'
356	    });
357	  }
358	
359	  /**
360	   * Выбрать активные item'ы, максимизируя покрытие KC (round-robin по KC), до `size`.
361	   * Если задан ctx (пер-KC mastery + недавние item'ы): слабые/неосвоенные KC идут первыми,
362	   * внутри KC — деприоритет недавно показанных (SR) и подбор сложности под уровень освоения.
363	   */
364	  private async selectCovering(
365	    subjectId: string,
366	    ktpTopicId: string,
367	    size: number,
368	    ctx?: { componentMap: Map<string, IUserKcComponentProgress>; recentItems: Set<string> }
369	  ) {
370	    const active = await QuestionItem.find({ subjectId, knowledgeNodeId: ktpTopicId, status: 'active' })
371	      .sort({ 'qualityStats.timesUsed': 1, createdAt: 1 })
372	      .lean();
373	    if (active.length === 0) return [];
374	
375	    // Группируем по KC (item без KC → ключ '_node').
376	    const byKc = new Map<string, typeof active>();
377	    for (const it of active) {
378	      const keys = (it.knowledgeComponentIds ?? []) as string[];
379	      const groupKeys = keys.length ? keys : ['_node'];
380	      for (const k of groupKeys) {
381	        if (!byKc.has(k)) byKc.set(k, []);
382	        byKc.get(k)!.push(it);
383	      }
384	    }
385	
386	    const masteryOf = (kcId: string): number => ctx?.componentMap.get(kcId)?.bestScore ?? 0;
387	    const isRecent = (id: string): boolean => ctx?.recentItems.has(id) ?? false;
388	
389	    // Порядок KC: слабые/неосвоенные первыми (по возрастанию bestScore).
390	    const kcKeys = [...byKc.keys()];
391	    if (ctx) kcKeys.sort((a, b) => masteryOf(a) - masteryOf(b));
392	
393	    // Внутри KC: не показанные недавно — первыми; сложность под уровень (слабому — проще).
394	    for (const k of kcKeys) {
395	      const weak = ctx ? masteryOf(k) < 80 : false;
396	      byKc.get(k)!.sort((x, y) => {
397	        if (ctx) {
398	          const rx = isRecent(String(x._id)) ? 1 : 0;
399	          const ry = isRecent(String(y._id)) ? 1 : 0;
400	          if (rx !== ry) return rx - ry; // не-недавние вперёд
401	          const dx = x.difficulty ?? 3;
402	          const dy = y.difficulty ?? 3;
403	          if (dx !== dy) return weak ? dx - dy : dy - dx; // слабому проще, сильному сложнее
404	        }
405	        return (x.qualityStats?.timesUsed ?? 0) - (y.qualityStats?.timesUsed ?? 0);
406	      });
407	    }
408	
409	    const picked: typeof active = [];
410	    const usedIds = new Set<string>();
411	    let progress = true;
412	    while (picked.length < size && progress) {
413	      progress = false;
414	      for (const k of kcKeys) {
415	        if (picked.length >= size) break;
416	        const pool = byKc.get(k)!;
417	        const next = pool.find((it) => !usedIds.has(String(it._id)));
418	        if (next) {
419	          usedIds.add(String(next._id));
420	          picked.push(next);
421	          progress = true;
422	        }
423	      }
424	    }
425	    return picked;
426	  }
427	}
