  roadmapNodeId?: string;
  /** По умолчанию ent — как раньше для API без поля */
  testProfile?: TestGenerationProfile;
  /** Формат ЕНТ: 10, 20, 40… (кратно 10, макс. 120). Пробник задаёт 20/10/10/40/40. */
  questionCount?: number;
